import cn from 'clsx'
import React from 'react'
import classes from '../style/index.module.styl'

export interface BlogLayoutNavigationPanelProps {
  /**
   * Navigation elements.
   */
  children: React.ReactNode
  /**
   * CSS class name
   */
  className?: string
}

export function BlogLayoutNavigationPanel(
  props: BlogLayoutNavigationPanelProps,
): React.ReactElement {
  const { children, className } = props
  return (
    <div className={cn(classes.navigationPanel, className)}>
      <div className={classes.navigationPanelNavWrapper}>{children}</div>
    </div>
  )
}

BlogLayoutNavigationPanel.displayName = 'BlogLayoutNavigationPanel'
export default BlogLayoutNavigationPanel
