import LinkRenderer from '@kyokuya/react-link'
import loadable from '@loadable/component'
import type { Definition, EcmaImport } from '@yozora/ast'
import { EcmaImportType, LinkReferenceType, LinkType } from '@yozora/ast'
import type {
  CodeRunnerItem,
  CodeRunnerProps,
  CodeRunnerScope,
} from '@yozora/react-code'
import type { CodeRendererJsxProps } from '@yozora/react-code-renderer-jsx'
import type { TokenRendererMap } from '@yozora/react-markdown'
import MathRenderer from '@yozora/react-math'
import type { Engine } from 'd3-graphviz'
import React, { useCallback, useEffect, useMemo, useState } from 'react'
import styled from 'styled-components'
import { lazyLoad } from './lazy'

const GraphvizRenderer = loadable(
  () => import('@yozora/react-code-renderer-graphviz'),
)
const JsxRenderer = loadable<CodeRendererJsxProps>(
  () => import('@yozora/react-code-renderer-jsx') as any,
)

export const customRendererMap: Partial<TokenRendererMap> = {
  [LinkType]: function renderLink(link, key, ctx) {
    const { url, title } = link
    return (
      <LinkRenderer key={key} url={url} title={title}>
        {ctx.renderNodes(link.children)}
      </LinkRenderer>
    )
  },
  [LinkReferenceType]: function renderLinkReference(linkReference, key, ctx) {
    const definition: Omit<Definition, 'type'> =
      ctx.getDefinition(linkReference.identifier) ?? ({} as any)
    const { url = '', title } = definition
    return (
      <LinkRenderer key={key} url={url} title={title}>
        {ctx.renderNodes(linkReference.children)}
      </LinkRenderer>
    )
  },
  [EcmaImportType]: () => null,
}

/**
 * Create code runners.
 * @returns
 */
export function useCodeRunners(
  ecmaImports: EcmaImport[],
  _jsxScope?: Readonly<CodeRunnerScope>,
): CodeRunnerItem[] {
  const customScopes = useMemo<CodeRunnerScope>(() => {
    const nextCustomScopes: CodeRunnerScope = {}
    const tasks: Array<Promise<void>> = []
    const fakeComponents: any[] = []

    for (const ecmaImport of ecmaImports) {
      const task: Promise<void> | null = lazyLoad(
        ecmaImport,
        nextCustomScopes,
        fakeComponents,
      )
      if (task === null) continue
      tasks.push(task)
    }

    nextCustomScopes.__fakeComponents = fakeComponents
    nextCustomScopes.__pending = Promise.all(tasks)
    return nextCustomScopes
  }, [ecmaImports])

  const codeRunners: CodeRunnerItem[] = useMemo<CodeRunnerItem[]>(() => {
    return [
      {
        title: 'jsx',
        pattern: /^jsx$/,
        runner: function JsxRunner(
          props: CodeRunnerProps,
        ): React.ReactElement | null {
          const { value, onError, meta = {} } = props
          const inline = meta.jsxMode == null || meta.jsxMode === 'inline'

          const __pending: Promise<void> | undefined =
            customScopes.__pending as any
          const [prepared, setPrepared] = useState<boolean>(
            !(__pending instanceof Promise),
          )

          useEffect(() => {
            if (prepared) return
            if (__pending instanceof Promise) {
              void __pending.then(() => setPrepared(true))
            }
          }, [prepared, __pending])

          const jsxScope: CodeRunnerScope = useMemo<CodeRunnerScope>(
            (): CodeRunnerScope => ({
              ..._jsxScope,
              ...customScopes,
              styled,
              useCallback,
              useEffect,
              useMemo,
              useState,
            }),
            [prepared],
          )

          if (!prepared) {
            const components = customScopes.__fakeComponents as any[]
            return components == null ? null : (
              <React.Fragment>
                {components.map((C, key) => (
                  <C key={key} className="hidden" />
                ))}
              </React.Fragment>
            )
          }

          return (
            <JsxRenderer
              code={value}
              inline={inline}
              scope={jsxScope}
              onError={onError}
            />
          )
        },
      },
      {
        title: 'graphviz',
        pattern: /^graphviz|dot$/,
        runner: function GraphvizRunner(
          props: CodeRunnerProps,
        ): React.ReactElement {
          const { value, meta = {}, onError } = props
          return (
            <GraphvizRenderer
              code={value}
              engine={meta.engine as Engine}
              onError={onError}
            />
          )
        },
      },
      {
        title: 'math',
        pattern: /^tex|latex|math|mathjax$/,
        runner: function MathJaxRunner(
          props: CodeRunnerProps,
        ): React.ReactElement {
          const value = props.value
            .replace(/^[\s\n]*([$]+)([\s\S]+)*\1[\s\n]*$/, '$2')
            .trim()
          return <MathRenderer value={value} />
        },
      },
    ]
  }, [_jsxScope, customScopes])
  return codeRunners
}

export default customRendererMap
