import GithubIcon from '@/component/icons/github'
import avatarImgUrl from '@/resource/image/avatar.jpg'
import Link from '@kyokuya/react-link'
import RssFeedOutlinedIcon from '@material-ui/icons/RssFeedOutlined'
import cn from 'clsx'
import React, { useContext, useMemo } from 'react'
import BlogContext from '../context'
import classes from '../style/index.module.styl'

export interface BlogLayoutSidebarProps {
  /**
   * Author's name.
   */
  authorName: string
  /**
   * Author's motto.
   */
  authorMotto: string
  /**
   * Github account url.
   */
  githubUrl: string
  /**
   * RSS feed url.
   */
  rssUrl: string
  /**
   * Home url
   */
  homeUrl: string
  /**
   * Url of pagination pages.
   */
  paginationUrl: string
}

export function BlogLayoutSidebar(
  props: BlogLayoutSidebarProps,
): React.ReactElement {
  const { authorName, authorMotto, githubUrl, rssUrl, paginationUrl, homeUrl } =
    props
  const { setMagicPanelVisible, setMagicPanelActivated } =
    useContext(BlogContext)

  const sidebar = useMemo(() => {
    const onNavigationClick: React.MouseEventHandler = e => {
      e.stopPropagation()
      setMagicPanelVisible(true)
      setMagicPanelActivated('navigation')
    }

    const onSearchClick: React.MouseEventHandler = e => {
      e.stopPropagation()
      setMagicPanelVisible(true)
      setMagicPanelActivated('search')
    }

    const onAboutMeClick: React.MouseEventHandler = e => {
      e.stopPropagation()
      setMagicPanelVisible(true)
      setMagicPanelActivated('about-me')
    }

    const sidebarNav = (
      <React.Fragment>
        <span key="home" className={classes.sidebarNavItem}>
          <Link url={paginationUrl}>文章</Link>
        </span>
        <span key="delimiter-1" className={classes.sidebarNavDelimiter} />
        <span
          key="navigation"
          className={classes.sidebarNavItem}
          onClick={onNavigationClick}
        >
          目录
        </span>
        <span key="delimiter-2" className={classes.sidebarNavDelimiter} />
        <span
          key="search"
          className={classes.sidebarNavItem}
          onClick={onSearchClick}
        >
          检索
        </span>
        <span key="delimiter-3" className={classes.sidebarNavDelimiter} />
        <span
          key="about-me"
          className={classes.sidebarNavItem}
          onClick={onAboutMeClick}
        >
          关于我
        </span>
      </React.Fragment>
    )

    return (
      <React.Fragment>
        <div className={cn(classes.sidebar, classes.frostedGlassPanel)}>
          <div className={classes.sidebarWrapper}>
            <header className={classes.sidebarHeader}>
              <div className={classes.sidebarOverlay} />
              <Link
                className={classes.sidebarAvatar}
                url={homeUrl}
                title="home"
              >
                <img alt="avatar" src={avatarImgUrl} />
              </Link>
              <h1 className={classes.sidebarAuthor}>
                <span onClick={onAboutMeClick}>{authorName}</span>
              </h1>
              <p className={classes.sidebarMotto}>{authorMotto}</p>
            </header>
            <div className={classes.sidebarBody}>
              <nav className={cn('hidden-xs', classes.sidebarNav)}>
                {sidebarNav}
              </nav>
              <nav className={classes.sidebarNavContact}>
                <Link
                  className={classes.sidebarNavContactItem}
                  url={githubUrl}
                  title="github"
                >
                  <GithubIcon />
                </Link>
                <Link
                  className={classes.sidebarNavContactItem}
                  url={rssUrl}
                  title="rss"
                >
                  <RssFeedOutlinedIcon />
                </Link>
              </nav>
              <nav className={cn('hidden-sm-plus', classes.sidebarNav)}>
                {sidebarNav}
              </nav>
            </div>
          </div>
        </div>
      </React.Fragment>
    )
  }, [
    authorName,
    authorMotto,
    githubUrl,
    rssUrl,
    homeUrl,
    paginationUrl,
    setMagicPanelVisible,
    setMagicPanelActivated,
  ])
  return sidebar
}

BlogLayoutSidebar.displayName = 'BlogLayoutSidebar'
export default BlogLayoutSidebar
