import { MathJaxProvider } from '@yozora/react-mathjax'
import cn from 'clsx'
import React, { useEffect, useState } from 'react'
import classes from './style.module.styl'

export interface TocItemData {
  /**
   * Toc depth
   */
  depth: number
  /**
   * Anchor identifier.
   */
  identifier: string
  /**
   * Toc title
   */
  title: React.ReactNode
}

export interface TocProps {
  /**
   * Activated identifier.
   */
  activatedIdentifier: string | null
  /**
   * Toc nodes
   */
  nodes: TocItemData[]
  /**
   * Pause watching scroll events.
   * @param timeout waiting duration (ms)
   */
  pauseWatchingScroll?(timeout: number): void
}

/**
 *
 * @param props
 */
export function Toc(props: TocProps): React.ReactElement {
  const { activatedIdentifier, nodes, pauseWatchingScroll } = props
  const [activatedIndex, setActivatedIndex] = useState<number>(0)

  useEffect(() => {
    const nextIndex: number = ((): number => {
      if (activatedIdentifier == null) return -1

      for (let i = 0; i < nodes.length; ++i) {
        if (nodes[i].identifier === activatedIdentifier) return i
      }

      // Don't change if no toc item matched.
      return -1
    })()

    if (nextIndex >= 0) setActivatedIndex(nextIndex)
  }, [activatedIdentifier, nodes])

  const handleClick = (index: number): void => {
    if (pauseWatchingScroll != null) {
      pauseWatchingScroll(1250)
    }
    setActivatedIndex(index)
  }

  return (
    <nav className={classes.toc}>
      <MathJaxProvider>
        <ul className={classes.tocList}>
          {nodes.map((node, index) => (
            <li
              key={node.identifier}
              style={{ paddingLeft: node.depth + 'rem' }}
              className={cn(classes.tocListItem, {
                [classes.tocListItemActive]: index === activatedIndex,
              })}
            >
              <a
                href={'#' + node.identifier}
                onClick={() => handleClick(index)}
              >
                {node.title}
              </a>
            </li>
          ))}
        </ul>
        <span
          className={classes.tocMarker}
          style={{ top: activatedIndex * 2 + 'rem' }}
        />
      </MathJaxProvider>
    </nav>
  )
}

export default Toc
