import cn from 'clsx';
import React from 'react';

function Delete(props) {
  var children = props.children,
      className = props.className,
      style = props.style;
  return React.createElement("del", {
    className: cn('yozora-delete', className),
    style: style
  }, children);
}

Delete.displayName = 'YozoraDelete';
export { Delete, Delete as default };