import React from 'react'
import classes from '../style/index.module.styl'

export interface BlogLayoutProps {
  /**
   * Date range of Copyright.
   */
  copyrightDate: string
  /**
   * Author's name.
   */
  authorName: string
  /**
   * Author's motto.
   */
  authorMotto: string
  /**
   * Main content.
   */
  content?: React.ReactNode
  /**
   * Footer content.
   */
  footer?: React.ReactNode
}

export function BlogLayoutMain(props: BlogLayoutProps): React.ReactElement {
  const { content, footer, copyrightDate, authorMotto, authorName } = props

  return (
    <div className={classes.main}>
      <div className={classes.mainContent}>
        {content}
        <footer className={classes.mainFooter}>
          <span>
            © {copyrightDate} {authorName}
          </span>
          <span>{authorMotto}</span>
        </footer>
        {footer}
      </div>
    </div>
  )
}

BlogLayoutMain.displayName = 'BlogLayoutMain'
export default BlogLayoutMain
